// Generate SRT captions from scene timeline data
const scenes = $('Load All Scenes').first().json;
const topic = $('Load Topic').first().json;
const topicData = Array.isArray(topic) ? topic[0] : topic;
const topicId = topicData.id || $('Webhook Trigger').item.json.body.topic_id;
const topicTitle = (topicData.seo_title || 'video').replace(/[^a-zA-Z0-9_\- ]/g, '').substring(0, 80);

const allScenes = Array.isArray(scenes) ? scenes : [scenes];

// Helper: convert milliseconds to SRT timestamp format HH:MM:SS,mmm
function msToSrt(ms) {
  const totalSeconds = Math.floor(ms / 1000);
  const hours = Math.floor(totalSeconds / 3600);
  const minutes = Math.floor((totalSeconds % 3600) / 60);
  const seconds = totalSeconds % 60;
  const millis = ms % 1000;
  return `${String(hours).padStart(2, '0')}:${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')},${String(millis).padStart(3, '0')}`;
}

let srtEntries = [];
let sequenceNum = 1;
let skippedCount = 0;
let totalDurationMs = 0;

for (const scene of allScenes) {
  const startMs = scene.start_time_ms || 0;
  const endMs = scene.end_time_ms || (startMs + (scene.audio_duration_ms || 0));
  const durationMs = scene.audio_duration_ms || (endMs - startMs);

  if (endMs > totalDurationMs) totalDurationMs = endMs;

  if (scene.skipped) {
    // Include skipped scenes with marker text
    srtEntries.push(`${sequenceNum}\n${msToSrt(startMs)} --> ${msToSrt(endMs)}\n[Scene skipped]\n`);
    sequenceNum++;
    skippedCount++;
    continue;
  }

  if (scene.narration_text && scene.narration_text.trim()) {
    srtEntries.push(`${sequenceNum}\n${msToSrt(startMs)} --> ${msToSrt(endMs)}\n${scene.narration_text.trim()}\n`);
    sequenceNum++;
  }
}

const srtContent = srtEntries.join('\n');

// Build scene processing list for clip building
const sceneList = allScenes.map(s => ({
  id: s.id,
  scene_number: s.scene_number,
  scene_id: s.scene_id,
  visual_type: s.visual_type,
  audio_duration_ms: s.audio_duration_ms || 0,
  audio_file_url: s.audio_file_url,
  audio_file_drive_id: s.audio_file_drive_id,
  image_url: s.image_url,
  image_drive_id: s.image_drive_id,
  video_url: s.video_url,
  video_drive_id: s.video_drive_id,
  skipped: s.skipped || false,
  padded_num: String(s.scene_number).padStart(3, '0')
}));

return [{
  json: {
    topic_id: topicId,
    project_id: topicData.project_id || allScenes[0]?.project_id,
    topic_title: topicTitle,
    topic_number: topicData.topic_number,
    drive_folder_id: topicData.drive_folder_id,
    drive_subfolder_ids: topicData.drive_subfolder_ids,
    srt_content: srtContent,
    srt_entry_count: sequenceNum - 1,
    scene_list: sceneList,
    total_scenes: sceneList.length,
    skipped_count: skippedCount,
    total_duration_ms: totalDurationMs,
    clips_built: 0,
    clips_failed: 0
  }
}];

// Write SRT file using Node.js fs for reliability (handles special chars)
const fs = require('fs');
const path = require('path');
const data = $('Generate SRT and Prepare').first().json;

const srtDir = `/tmp/production/${data.topic_id}/captions`;
fs.mkdirSync(srtDir, { recursive: true });
fs.writeFileSync(path.join(srtDir, `${data.topic_title}.srt`), data.srt_content, 'utf8');

// Also create all needed directories
const dirs = ['clips', 'final', 'audio', 'images', 'video_clips'];
for (const dir of dirs) {
  fs.mkdirSync(`/tmp/production/${data.topic_id}/${dir}`, { recursive: true });
}

return [{ json: { ...data, srt_path: path.join(srtDir, `${data.topic_title}.srt`) } }];

// Convert scene_list to individual items for SplitInBatches
const data = $input.first().json;
const items = data.scene_list.map(scene => ({
  json: {
    ...scene,
    topic_id: data.topic_id,
    project_id: data.project_id,
    topic_title: data.topic_title,
    total_scenes: data.total_scenes
  }
}));
return items;

// Determine the FFmpeg command for this scene based on visual_type and skipped status
const scene = $input.first().json;
const topicId = scene.topic_id;
const padded = scene.padded_num;
const durationSec = (scene.audio_duration_ms / 1000).toFixed(3);

const audioPath = `/tmp/production/${topicId}/audio/scene_${padded}.mp3`;
const imagePath = `/tmp/production/${topicId}/images/scene_${padded}.png`;
const videoPath = `/tmp/production/${topicId}/video_clips/scene_${padded}.mp4`;
const outputPath = `/tmp/production/${topicId}/clips/scene_${padded}.mp4`;

let ffmpegCmd = '';
let needsDownload = { audio: false, image: false, video: false };

if (scene.skipped) {
  // Black frame with white '[Scene skipped]' text
  ffmpegCmd = `ffmpeg -y -f lavfi -i color=c=black:s=1920x1080:r=30:d=${durationSec} -i ${audioPath} -vf "drawtext=text='[Scene skipped]':fontcolor=white:fontsize=48:x=(w-text_w)/2:y=(h-text_h)/2" -c:v libx264 -preset fast -crf 23 -pix_fmt yuv420p -c:a aac -b:a 128k -r 30 -t ${durationSec} -movflags +faststart ${outputPath}`;
  needsDownload.audio = true;
} else if (scene.visual_type === 'static_image') {
  // Static image displayed for audio duration
  ffmpegCmd = `ffmpeg -y -loop 1 -i ${imagePath} -i ${audioPath} -c:v libx264 -preset fast -crf 23 -pix_fmt yuv420p -c:a aac -b:a 128k -vf "scale=1920:1080:force_original_aspect_ratio=decrease,pad=1920:1080:(ow-iw)/2:(oh-ih)/2" -r 30 -t ${durationSec} -movflags +faststart ${outputPath}`;
  needsDownload.audio = true;
  needsDownload.image = true;
} else if (scene.visual_type === 'i2v' || scene.visual_type === 't2v') {
  // Video scene - loop if audio > 5s, trim if <= 5s
  if (scene.audio_duration_ms > 5000) {
    ffmpegCmd = `ffmpeg -y -stream_loop -1 -i ${videoPath} -i ${audioPath} -c:v libx264 -preset fast -crf 23 -pix_fmt yuv420p -c:a aac -b:a 128k -vf "scale=1920:1080:force_original_aspect_ratio=decrease,pad=1920:1080:(ow-iw)/2:(oh-ih)/2" -r 30 -t ${durationSec} -movflags +faststart ${outputPath}`;
  } else {
    ffmpegCmd = `ffmpeg -y -i ${videoPath} -i ${audioPath} -c:v libx264 -preset fast -crf 23 -pix_fmt yuv420p -c:a aac -b:a 128k -vf "scale=1920:1080:force_original_aspect_ratio=decrease,pad=1920:1080:(ow-iw)/2:(oh-ih)/2" -r 30 -t ${durationSec} -movflags +faststart ${outputPath}`;
  }
  needsDownload.audio = true;
  needsDownload.video = true;
} else {
  // Fallback: treat as static image
  ffmpegCmd = `ffmpeg -y -loop 1 -i ${imagePath} -i ${audioPath} -c:v libx264 -preset fast -crf 23 -pix_fmt yuv420p -c:a aac -b:a 128k -vf "scale=1920:1080:force_original_aspect_ratio=decrease,pad=1920:1080:(ow-iw)/2:(oh-ih)/2" -r 30 -t ${durationSec} -movflags +faststart ${outputPath}`;
  needsDownload.audio = true;
  needsDownload.image = true;
}

return [{
  json: {
    ...scene,
    ffmpeg_cmd: ffmpegCmd,
    output_path: outputPath,
    audio_path: audioPath,
    image_path: imagePath,
    video_path: videoPath,
    needs_download: needsDownload,
    duration_sec: parseFloat(durationSec)
  }
}];

// Download required assets from Google Drive or URLs
// In n8n, Google Drive downloads happen via Google Drive node or HTTP Request
// Here we build the download commands for Execute Command
const scene = $input.first().json;
const needs = scene.needs_download;
const topicId = scene.topic_id;
const padded = scene.padded_num;

let downloadCmds = [];

if (needs.audio && scene.audio_file_url) {
  // Download audio from Drive URL or direct URL
  downloadCmds.push(`curl -sL -o /tmp/production/${topicId}/audio/scene_${padded}.mp3 "${scene.audio_file_url}"`);
} else if (needs.audio && scene.audio_file_drive_id) {
  // Download from Google Drive using drive export link
  downloadCmds.push(`curl -sL -o /tmp/production/${topicId}/audio/scene_${padded}.mp3 "https://www.googleapis.com/drive/v3/files/${scene.audio_file_drive_id}?alt=media"`);
}

if (needs.image && scene.image_url) {
  downloadCmds.push(`curl -sL -o /tmp/production/${topicId}/images/scene_${padded}.png "${scene.image_url}"`);
} else if (needs.image && scene.image_drive_id) {
  downloadCmds.push(`curl -sL -o /tmp/production/${topicId}/images/scene_${padded}.png "https://www.googleapis.com/drive/v3/files/${scene.image_drive_id}?alt=media"`);
}

if (needs.video && scene.video_url) {
  downloadCmds.push(`curl -sL -o /tmp/production/${topicId}/video_clips/scene_${padded}.mp4 "${scene.video_url}"`);
} else if (needs.video && scene.video_drive_id) {
  downloadCmds.push(`curl -sL -o /tmp/production/${topicId}/video_clips/scene_${padded}.mp4 "https://www.googleapis.com/drive/v3/files/${scene.video_drive_id}?alt=media"`);
}

return [{
  json: {
    ...scene,
    download_cmd: downloadCmds.length > 0 ? downloadCmds.join(' && ') : 'echo "No downloads needed"'
  }
}];

// Track clip completion/failure counts using workflow static data
const staticData = $getWorkflowStaticData('global');
if (!staticData.clips_built) staticData.clips_built = 0;
if (!staticData.clips_failed) staticData.clips_failed = 0;
staticData.clips_built++;
return [{ json: { clips_built: staticData.clips_built, status: 'complete' } }];

// Track clip failure count
const staticData = $getWorkflowStaticData('global');
if (!staticData.clips_built) staticData.clips_built = 0;
if (!staticData.clips_failed) staticData.clips_failed = 0;
staticData.clips_failed++;
return [{ json: { clips_failed: staticData.clips_failed, status: 'failed', error: $('Build Scene Clip').item.json.stderr || 'FFmpeg error' } }];

// Generate concat.txt file listing all scene clips in order
const fs = require('fs');
const data = $('Write SRT File').first().json;
const topicId = data.topic_id;
const totalScenes = data.total_scenes;

let concatLines = [];
for (let i = 1; i <= totalScenes; i++) {
  const padded = String(i).padStart(3, '0');
  const clipPath = `/tmp/production/${topicId}/clips/scene_${padded}.mp4`;

  // Only include clips that exist (skip failed ones that weren't built)
  try {
    fs.accessSync(clipPath);
    concatLines.push(`file '${clipPath}'`);
  } catch (e) {
    // Clip missing - skip it in concat
  }
}

const concatContent = concatLines.join('\n');
const concatPath = `/tmp/production/${topicId}/concat.txt`;
fs.writeFileSync(concatPath, concatContent, 'utf8');

return [{
  json: {
    topic_id: topicId,
    project_id: data.project_id,
    topic_title: data.topic_title,
    concat_path: concatPath,
    clips_in_concat: concatLines.length,
    total_scenes: totalScenes,
    skipped_count: data.skipped_count,
    srt_path: data.srt_path,
    drive_folder_id: data.drive_folder_id,
    drive_subfolder_ids: data.drive_subfolder_ids
  }
}];

// Read the final video file as binary for Google Drive upload
const fs = require('fs');
const data = $('Generate Concat List').first().json;
const finalPath = `/tmp/production/${data.topic_id}/final/${data.topic_title}.mp4`;

const fileBuffer = fs.readFileSync(finalPath);
const binaryData = {
  data: {
    data: fileBuffer.toString('base64'),
    mimeType: 'video/mp4',
    fileName: `${data.topic_title}.mp4`
  }
};

return [{ json: { ...data }, binary: binaryData }];

// Read SRT file as binary for Google Drive upload
const fs = require('fs');
const data = $('Generate Concat List').first().json;
const srtPath = data.srt_path;

const srtBuffer = fs.readFileSync(srtPath);
const binaryData = {
  data: {
    data: srtBuffer.toString('base64'),
    mimeType: 'text/plain',
    fileName: `${data.topic_title}.srt`
  }
};

return [{ json: { ...data }, binary: binaryData }];
